"""
mkt-christ commentary: Jeremiah 33-36 (99 verses)
Layer: christ — Christological fulfillment, typology, NT citation patterns
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST_33 = {
  "1": "<p>The word comes to Jeremiah while he is confined in the court of the guard — the prophetic word is not silenced by imprisonment. Christ spoke from the ultimate confinement: the cross and the tomb were the world's attempt to silence the divine word, but the word that came while confined is the word that proved unkillable. Paul writes from prison (Phil 1:12-14) that his confinement has advanced the gospel; the imprisoned prophet is a recurrent pattern for the unstoppable word of God.</p>",
  "2": "<p>The LORD identifies himself as the maker, former, and establisher of the earth — three creation verbs that ground the restoration promise in divine omnipotence. John's prologue applies this creator identity to Christ: 'All things were made through him, and without him was not anything made that was made' (John 1:3). The one who makes the restoration promise is the same one through whom the earth was originally made; the new creation is the work of the same creator-Word who spoke the first creation into being.</p>",
  "3": "<p>'Call to me and I will answer you, and will tell you great and hidden things that you have not known.' Jesus reframes this as the heart of the new covenant's access: 'Ask and it will be given to you' (Matt 7:7); 'Whatever you ask in my name, this I will do' (John 14:13). The 'great and hidden things' (<em>bĕṣūrôt</em>) — hidden, inaccessible truths — are what Paul calls 'the mystery hidden for ages' now revealed in Christ (Col 1:26-27): the indwelling of Christ in believers, the calling of the Gentiles, the fullness of the gospel.</p>",
  "4": "<p>Houses of city and kings torn down for siege ramps — destruction in judgment. The temple that stood as the false security of Jerusalem was torn down; Christ himself identified his body as the true temple (John 2:19-21), and the destruction of Herod's temple in 70 CE is predicted by Jesus as the consequence of rejecting him (Matt 24:2; Luke 19:43-44). The rubble of Jerusalem's houses is the rubble of every human structure that substitutes for the presence of God incarnate.</p>",
  "5": "<p>'I have hidden my face from this city because of all their wickedness.' The divine hiddenness — the withdrawal of the Shekinah — is the deepest judgment. On the cross Jesus cried 'My God, my God, why have you forsaken me?' (Matt 27:46), entering the condition of God-forsakenness that Jerusalem experienced in the exile. Christ underwent the full weight of the hidden face of God — not merely as a metaphor but as the representative bearer of all the sin that caused the hiding.</p>",
  "6": "<p>'Behold I will bring health and healing to it; I will heal them and reveal to them an abundance of prosperity and security.' Jesus opens his ministry quoting Isaiah 61 (Luke 4:18): 'He has sent me to proclaim good news to the poor, to bind up the brokenhearted.' Every healing in the Gospels is a concrete sign of this restoration promise: the healings are not merely compassionate acts but demonstrations that the kingdom of restoration — the shalom YHWH promised — has arrived in the person of the healer.</p>",
  "7": "<p>'I will restore the fortunes of Judah and Israel and rebuild them as they were at the beginning.' Paul's vision in 2 Cor 5:17 is the Christological fulfillment: 'If anyone is in Christ he is a new creation; the old has passed away; behold the new has come.' The rebuild 'as at the beginning' gestures toward the original Edenic purpose — which Christ restores not merely by returning to Eden but by surpassing it. The new creation in Christ is better than the original: Eden had no cross, no resurrection, no indwelling Spirit.</p>",
  "8": "<p>'I will cleanse them from all the iniquity by which they sinned against me, and I will forgive all the iniquity and rebellion.' Hebrews applies this forgiveness promise directly to Christ's atonement: 'For by a single offering he has perfected for all time those who are being sanctified' (Heb 10:14); 'I will remember their sins and their lawless deeds no more' (Heb 10:17, citing Jer 31:34). The forgiveness Jeremiah promises is not achieved by exile and return but by the definitive sacrifice of the Son — the blood that speaks better than Abel's (Heb 12:24).</p>",
  "9": "<p>'This city will be to me a name of joy, a praise, and a glory before all the nations.' Philippians 2:9-11 transfers the honor-before-all-nations to Christ: 'God has highly exalted him and bestowed on him the name that is above every name, so that at the name of Jesus every knee should bow, of those in heaven and on earth.' Jerusalem's calling to be a praise before the nations is fulfilled eschatologically in the Lamb — Revelation pictures the nations bringing their glory into the New Jerusalem (Rev 21:26), but the city's glory is the Lamb himself (Rev 21:23).</p>",
  "10": "<p>'In this place that you are calling a waste — without man or beast.' The silence of desolation is the silence of the grave: the ruined city is a figure of death. But into the silence of death comes the voice that says 'there shall again be heard ...' — the resurrection voice. Jesus's entry into the silence of death (the tomb) is the entry into the world's ultimate desolation; his resurrection is the voice that ends the silence and begins the new song.</p>",
  "11": "<p>'The voice of joy and the voice of gladness, the voice of the bridegroom and the voice of the bride.' John the Baptist identifies himself as the friend of the bridegroom who rejoices when he hears the bridegroom's voice (John 3:29). Christ is the bridegroom; the church is the bride (Eph 5:25-32; Rev 19:7-9). The eschatological wedding feast prophesied here is the marriage supper of the Lamb — the fullness of which the Lord's Supper is the advance foretaste: 'Give thanks to the LORD for his steadfast love endures forever' is the eucharistic cry of those who know the cross is that love's ultimate expression.</p>",
  "12": "<p>'There will again be pastures where shepherds rest their flocks.' Jesus the Good Shepherd (John 10:11) makes the sheep lie down in green pastures (Ps 23:2) — the rest imagery is consistently Christological. Hebrews 4:9-10 reads the rest that remains for the people of God through the lens of Christ's completed work: the one who has entered his rest has also rested from his works as God did from his. The desolate places will be places of rest because the Good Shepherd who laid down his life makes rest possible.</p>",
  "13": "<p>'The flocks shall once more pass under the hands of the one who counts them.' The counter of the flock is Christ, who says 'I know my own and my own know me' (John 10:14) and 'I give them eternal life and they will never perish, and no one will snatch them out of my hand' (John 10:28-29). The numbering of the sheep is the security of election: every sheep that passes under the shepherd's hand is known, counted, and secured — nothing in all creation can separate them from the love of God in Christ Jesus (Rom 8:38-39).</p>",
  "14": "<p>'The days are coming when I will fulfill the good promise I made to the house of Israel and the house of Judah.' Paul's great Christological affirmation: 'For all the promises of God find their Yes in him' (2 Cor 1:20). Every promise in the Hebrew scriptures — return from exile, restoration of fortunes, new covenant, righteous branch, eternal kingdom — finds its fulfillment not in the return under Zerubbabel (which was partial) but in Jesus Christ. The 'days are coming' of Jeremiah's prophecy have come in the person of the Son.</p>",
  "15": "<p>A direct messianic fulfillment: 'I will cause a righteous <strong>ṣemaḥ ṣaddîq</strong> (<em>ṣemaḥ ṣaddîq</em>) to spring up for David, and he shall execute justice and righteousness in the land.' <em>Ṣemaḥ</em> (Branch, Sprout) is the specific messianic title Zechariah uses twice (Zech 3:8; 6:12), and Revelation applies to Christ: 'the root and the offspring of David' (Rev 5:5; 22:16). The Branch who springs up is not merely a king who does justice but the one who IS righteousness for his people — 1 Cor 1:30: 'Christ Jesus, whom God made our wisdom and our righteousness.' The righteous Branch is the one who justifies the ungodly (Rom 4:5).</p>",
  "16": "<p>'And this is the name by which it will be called: YHWH ṣidqênû — The LORD is our righteousness.' Paul identifies this promise with Christ: 'Christ is the end of the law for righteousness to everyone who believes' (Rom 10:4); 'God made him to be sin who knew no sin, so that in him we might become the righteousness of God' (2 Cor 5:21). The name YHWH ṣidqênû, given to the restored Jerusalem, is the name of Christ's people because they are clothed in him — their righteousness is not their own but the Lord's, reckoned to them through faith in the Branch.</p>",
  "17": "<p>'There will never fail to be a man from David's line to sit on the throne of the house of Israel.' The angel Gabriel applies this promise to Jesus at the annunciation: 'The Lord God will give to him the throne of his father David, and he will reign over the house of Jacob forever, and of his kingdom there will be no end' (Luke 1:32-33). Peter at Pentecost makes the connection explicit: David was a prophet and 'seeing what was ahead, he spoke of the resurrection of Christ' — the one who now sits on David's throne does so by virtue of the resurrection (Acts 2:29-31). The unbroken Davidic succession is Jesus.</p>",
  "18": "<p>'The Levitical priests shall never lack a man in my presence to offer burnt offerings.' The royal Davidic covenant and the Levitical priestly covenant are here inseparably linked — both are as permanent as the cosmos. Hebrews resolves the puzzle of how Jesus, from the tribe of Judah, fulfills the Levitical promise: he is priest not by the Levitical order of physical descent but by the Melchizedekian order of indestructible life (Heb 7:14-17). He combines in himself both the royal Davidic promise (v. 17) and the perpetual priestly promise (v. 18) — king and priest in one person, the thing the law could not do but Christ has done.</p>",
  "19": "<p>The word of the LORD came to Jeremiah — the prophetic word is the pre-incarnate communication of the Son who is the eternal Word. John 1:1 establishes the Logos as the ground of all divine speech: every time 'the word of the LORD came,' it was the eternal Word — who would become flesh — who was speaking. The frequency of this formula in Jeremiah (over 50 times) marks the book as saturated with the pre-incarnate Christ's communicative activity.</p>",
  "20": "<p>'If you can break my covenant with the day and my covenant with the night, so that day and night no longer come at their appointed time.' The cosmic orders that sustain creation are the guarantors of the Davidic-priestly covenant. Paul's 'nothing in all creation will be able to separate us from the love of God in Christ Jesus our Lord' (Rom 8:38-39) is the new covenant expression of the same logic: the love revealed in the cross is as indestructible as the cosmos — more so, because the cosmos itself will be renewed (Rev 21:1) but Christ's love never changes.</p>",
  "21": "<p>'Then my covenant with my servant David could also be broken, so that he would no longer have a son to reign on his throne.' The Davidic covenant's eternality is secured by the resurrection: the Son who reigns on David's throne is the one whom death could not hold (Acts 2:24). The resurrection is God's pledge that the covenant cannot be broken — 'the God of peace who brought again from the dead our Lord Jesus, the great shepherd of the sheep, by the blood of the eternal covenant' (Heb 13:20). The risen Christ is the living proof that the Davidic covenant stands.</p>",
  "22": "<p>'As the host of heaven cannot be numbered and the sand of the sea cannot be measured, so I will multiply the offspring of David my servant and the Levites who minister to me.' Galatians 3:16 focuses the seed promise: 'It does not say seeds, referring to many, but referring to one, and to your offspring, who is Christ.' All who are in Christ are Abraham's offspring and heirs of the promise (Gal 3:29) — the multiplication happens through union with the one seed. The countless host of the redeemed in Revelation (7:9: a great multitude that no one could number) is the fulfillment: the seed multiplied through Christ.</p>",
  "23": "<p>The word of the LORD came — the repeated formula of divine communication. Christ is the Word who speaks through the prophets (Heb 1:1) and who is himself the final, definitive speech (Heb 1:2: 'in these last days he has spoken to us by his Son'). Each prophetic word-reception is a type of the incarnation: God communicating to the human through a human vessel, until the vessel and the word become identical in the person of the Son.</p>",
  "24": "<p>'The LORD has rejected the two families he chose' — the people's despairing conclusion. Romans 9-11 addresses precisely this question: has God rejected his people? Paul's answer is no — a remnant chosen by grace remains, and the hardening of Israel is partial and temporary, serving the purpose of Gentile inclusion (Rom 11:1-2, 11-12, 25-26). The apparent rejection of the two families during the exile and in the present age is not God's final word; the final word is the one who says 'I will restore their fortunes' (v. 26).</p>",
  "25": "<p>'If I have not established my covenant with day and night and the fixed orders of heaven and earth.' Colossians 1:17 identifies Christ as the one in whom 'all things hold together' — the fixed orders of creation subsist in the Son's sustaining power (Heb 1:3: he upholds the universe by the word of his power). The cosmic-covenant logic runs both ways: the Creator who sustains the cosmos is the same one who sustains the covenant; both rest on the faithfulness of Christ.</p>",
  "26": "<p>'I will restore their fortunes and have mercy on them.' The divine 'I will' of covenantal mercy is the heartbeat of Paul's argument in Romans 11:26-27: 'The deliverer will come from Zion, he will banish ungodliness from Jacob; and this will be my covenant with them when I take away their sins.' The restoration of Israel's fortunes is eschatologically achieved through Christ — the deliverer who has come and will come again. All mercy flows through the Son who embodies it (Luke 1:78: the tender mercy of our God).</p>"
}

CHRIST_34 = {
  "1": "<p>Nebuchadnezzar and all his army fighting against Jerusalem — the siege is the divine instrument of covenant judgment. The gospel's logic follows: Jerusalem under siege is Israel under the weight of covenant failure, which is the human condition apart from Christ. The nations that surround and threaten are the powers of sin, death, and accusation. Christ enters into the full siege of human existence — 'born under the law' (Gal 4:4) — in order to bear the judgment from within.</p>",
  "2": "<p>'I am going to hand this city over to the king of Babylon, and he will burn it with fire.' The vocabulary of 'handing over' (Hebrew <em>nātan</em>) is the NT's vocabulary of the passion: God 'did not spare his own Son but gave him up for us all' (Rom 8:32); Jesus is 'delivered over to death for our trespasses' (Rom 4:25). The city's being handed over to judgment is the type of Christ being handed over to the judgment that should have fallen on the city — on us.</p>",
  "3": "<p>Zedekiah will be captured, see the king face to face, and go to Babylon. The face-to-face encounter with the conquering king is the figure of the last judgment — every person will stand before the King (Matt 25:31-32). But Christ's mediation transforms the encounter: those who are in him will not face condemnation (Rom 8:1) because he faced the full encounter with divine judgment on their behalf. What Zedekiah faced in surrender to Babylon, Christ faced in surrender to the cross.</p>",
  "4": "<p>'Yet hear the word of the LORD, O Zedekiah ... you will not die by the sword.' In the midst of judgment, a word of specific grace. God addresses individuals with particular promises even within general judgment. Jesus's individual address — to the thief on the cross ('today you will be with me in paradise', Luke 23:43), to Zacchaeus ('today salvation has come to this house', Luke 19:9) — is the continuation of this pattern: the word of the LORD reaches specific people with particular assurance even in the hour of judgment.</p>",
  "5": "<p>'You will die in peace.' The paradox: Zedekiah loses his kingdom and his sons but is promised a peaceful death. Christ's peace 'which surpasses all understanding' (Phil 4:7) is given precisely in the conditions of earthly loss, imprisonment, and apparent defeat. Paul and Silas in prison sing hymns at midnight (Acts 16:25); the peace of God is not contingent on external circumstances because it rests on the finished work of Christ — the true Davidic king who gives the peace that the world cannot give (John 14:27).</p>",
  "6": "<p>Jeremiah spoke all these words to Zedekiah — the faithful prophet delivering an unwelcome word to a failing king. Jesus is the faithful and true witness (Rev 3:14) who speaks truth to power — before Pilate, before the Sanhedrin, in the temple courts — without accommodation. The prophetic pattern of unwelcome truth-telling reaches its climax in Christ, who speaks not only God's word but IS the Word of God, and is rejected and killed for it.</p>",
  "7": "<p>Only Lachish and Azekah still hold out — the archaeological record (the Lachish letters) confirms this final-days situation. Historical specificity grounds the theological pattern: the incarnation takes place in specific historical conditions, not in the realm of timeless myth. Luke 2's 'in those days' and John 19's 'it was the day of Preparation for the Passover' insist on the same historicity — the Word became flesh in real time, real geography, real political crisis.</p>",
  "8": "<p>Zedekiah made a covenant to proclaim <strong>dĕrôr</strong> (<em>dĕrôr</em>) — liberty — to all Hebrew slaves. Jesus in the Nazareth synagogue reads Isaiah 61:1-2: 'The Spirit of the Lord is upon me ... to proclaim liberty (<em>dĕrôr</em> in Hebrew; <em>aphesin</em> in LXX/Luke) to the captives' (Luke 4:18-19). He then says: 'Today this Scripture has been fulfilled in your hearing.' The Jubilee proclamation of release — which Zedekiah's court enacts and then revokes — is what Christ enacts once and for all and can never revoke: the liberty he proclaims to the captives is permanent (Gal 5:1: for freedom Christ has set us free).</p>",
  "9": "<p>'Everyone was to release his Hebrew male slave and his Hebrew female slave, so that no one would keep a fellow Hebrew in slavery.' The freedom proclaimed covers the nearest — the fellow Hebrew — but Jesus extends the liberation to all (Gal 3:28: neither Jew nor Greek, slave nor free). The scope of Christ's liberating proclamation transcends ethnic and social boundaries; all who were enslaved to sin are set free by the Son (John 8:34-36: if the Son sets you free, you will be free indeed).</p>",
  "10": "<p>All the officials and people obeyed — they released their slaves. The initial response to the word is positive; compliance and liberation happen. This mirrors the initial joyful reception of the gospel in many hearts — the seed falls on rocky ground that springs up quickly (Matt 13:20-21). The test of true liberation is not the initial response but whether the freedom holds under pressure.</p>",
  "11": "<p>'But afterward they turned back and took back the male and female slaves they had freed, forcing them back into slavery.' This is the catastrophic failure of human-willed liberation: when it costs something (the siege temporarily lifted, and the slaves were economically useful), the masters revoked the freedom. The permanence of Christ's liberation is its decisive contrast: 'For sin will have no dominion over you, since you are not under law but under grace' (Rom 6:14). The liberation Christ grants cannot be revoked by human fear or selfishness — it is secured by blood, not by covenant-keeping effort.</p>",
  "12": "<p>The word of the LORD came to Jeremiah — divine response to the covenant-breaking. God does not remain silent when his covenant is violated; he speaks with clarity about the consequences. Jesus's warnings in Matthew 23 and 24 follow the same pattern: the rejected prophets, the violated covenant, the coming judgment, spoken with prophetic urgency. The God who speaks through Jeremiah is the same one who speaks in his Son (Heb 1:1-2).</p>",
  "13": "<p>'I made a covenant with your ancestors when I brought them out of Egypt, out of the house of slavery.' The Exodus covenant is the basis of the freedom obligation. Paul reads the Exodus through Christ as the new Exodus: 'Our fathers were all under the cloud, and all passed through the sea, and all were baptized into Moses ... These things happened to them as examples, but they were written down for our instruction' (1 Cor 10:1-11). Christ is the true liberator from 'the house of slavery' (Rom 6:17-18: you were slaves of sin but have become obedient from the heart).</p>",
  "14": "<p>'At the end of seven years, every one of you must release a fellow Hebrew.' The sabbatical year liberation foreshadows Christ's Jubilee proclamation (Luke 4:18-19) and the final rest of Hebrews 4. The principle of the seventh year — rest and release after six years of labor — is fulfilled in Christ's completed work: 'It is finished' (John 19:30) is the declaration of the sabbath rest that follows the six days of creation-work. The one who finished the work of redemption is the one who grants the permanent release the sabbatical year only pointed toward.</p>",
  "15": "<p>'Just recently you turned back and did what was right in my eyes, each of you proclaiming liberty to your neighbor. You made a covenant before me in the house that bears my name.' The house bearing God's name is the temple; Jesus identified his body as the true temple (John 2:19-21). The covenant made in the house bearing God's name is now enacted in the body of Christ — the new covenant sealed by his blood in the new temple of his flesh. The liberty proclaimed in the old temple's precincts is fulfilled by the one who is both the temple and the covenant-maker.</p>",
  "16": "<p>'You profaned my name: each of you took back the male and female slaves you had set free.' Profaning the divine name by covenant-breaking is the logic Paul addresses in Romans 6: 'Shall we continue in sin that grace may abound? By no means!' (Rom 6:1-2). The freedom of the gospel is not a license to return to slavery — to return to sin after liberation is precisely the profaning of the name that freed us. The permanence of Christ's liberation requires a permanent response of freedom-living.</p>",
  "17": "<p>'You have not obeyed me by proclaiming liberty, each to his brother and to his neighbor. So now I am proclaiming liberty for you — liberty to the sword, to pestilence, and to famine.' The ironic inversion: refuse to grant liberty to others, receive 'liberty' to destruction. Galatians 5:13 contains the counterpart: 'You were called to freedom, brothers. Only do not use your freedom as an opportunity for the flesh, but through love serve one another.' The liberty Christ grants is not a freedom from obligation but a freedom for love-service — using freedom to free others.</p>",
  "18": "<p>'The men who violated my covenant ... when they cut the calf in two and passed between its parts.' The covenant-cutting ceremony of Genesis 15 is recalled: God (as a smoking firepot and flaming torch) passed between the pieces, taking the covenant oath on himself. Hebrews 9:15-22 reads the inauguration of covenants through death: 'Not even the first covenant was inaugurated without blood.' Christ, as the mediator of the new covenant, passes through death itself — not symbolically between the halves of an animal but actually through the valley of death — to ratify the covenant by his own blood.</p>",
  "19": "<p>All classes — officials, priests, people — who passed between the calf parts are now subject to the calf's fate: to be cut in two. Covenant violation brings covenant curse. Christ bore the covenant curse for his people: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The curse-logic of the covenant cutting is not abolished but fulfilled — absorbed into the body of the one who passed through death so that we would not have to.</p>",
  "20": "<p>'Their dead bodies will become food for the birds of the sky and the beasts of the earth.' The final shame of the covenant-breakers — exposed and unburied. The cross appears to be this same shame: Jesus's body exposed on the tree. But the resurrection reverses the shame into glory (Phil 2:9-11): the body that hung on the cross is now the glorified body at the right hand of God. The resurrection is God's refusal to let the covenant-mediator's body be subject to the dishonor of unburial and corruption (Acts 2:27, 31: God did not abandon him to Hades or let his body see corruption).</p>",
  "21": "<p>Zedekiah and his officials given to their enemies — the king who fails to maintain the covenant is himself given over to the very judgment he was supposed to prevent. But in the new covenant, the one who is given over to the enemy (Rom 8:32: he did not spare his own Son but gave him up for us all) is not a covenant-breaker but the perfectly faithful covenant-keeper who is given over on behalf of the breakers. The substitution is total: the righteous given over for the unrighteous (1 Pet 3:18).</p>",
  "22": "<p>'I am about to give the command, and I will bring them back to this city ... and burn it with fire. I will make the cities of Judah a desolation without inhabitant.' The finality of judgment on covenant-breaking. But beyond the desolation lies the word of Jeremiah 33: the desolate cities will again hear the voice of joy and gladness (33:10-11). The gospel's structure is identical: the cross is the desolation, the silencing, the burning — and then the resurrection is the voice that ends the desolation and repopulates the waste places with the new creation.</p>"
}

CHRIST_35 = {
  "1": "<p>The Rechabite episode is set in the days of Jehoiakim — the king who will burn the scroll in chapter 36. The contrast is structural: the Rechabites who obey a human father's command are set against Judah's disobedience to the divine Father's commands. Jesus teaches the same contrast in John 5:19-20: the Son does only what he sees the Father doing, bound to the Father's will by perfect filial obedience — the obedience the Rechabites model in human form and that Jesus perfects in divine-human form.</p>",
  "2": "<p>'Go to the house of the Rechabites.' The Rechabites are brought into the temple precincts — nomadic outsiders brought into the sacred space. The Gentile mission pattern: those who were 'outside' the covenant community are brought in and given access to the house of God. Christ 'has broken down the dividing wall of hostility' (Eph 2:14) and brought the far-off near (Eph 2:13), so that all peoples have access to the inner rooms of the divine presence.</p>",
  "3": "<p>Jaazaniah and the whole house of the Rechabites — an extended family community of covenantal faithfulness. The church as the new covenant family is the Christological counterpart: those who do the will of Christ's Father are his brother and sister and mother (Matt 12:50). Family identity in the kingdom is constituted not by biological descent but by shared covenant obedience — the Rechabite pattern applied universally through adoption in Christ (Rom 8:15-16).</p>",
  "4": "<p>Brought into the temple, into the inner rooms — the innermost chambers of the sacred space. Hebrews 10:19-22 is the theological climax: 'Since we have confidence to enter the holy places by the blood of Jesus, by the new and living way that he opened for us through the curtain, that is, through his flesh ... let us draw near.' The inner room that only the high priest could enter once a year is now the open access of all who come through Christ — the veil torn (Matt 27:51), the way into the most holy place made permanently open.</p>",
  "5": "<p>Pitchers full of wine and cups set before the Rechabites — the test of obedience through temptation. The Lord's Supper places wine on the table as the cup of the new covenant (Luke 22:20): the cup that represents Christ's blood shed for the forgiveness of sins. The Rechabites who refused the wine of worldly accommodation are the type of those who, in contrast, receive the wine of the new covenant with gratitude — the cup that Jesus himself drank to its dregs (John 18:11: 'Shall I not drink the cup the Father has given me?').</p>",
  "6": "<p>'We will not drink wine, for Jonadab son of Rechab, our father, commanded us.' The obedience to the father's command across generations is the pattern of Christ's obedience to his Father: 'For I have not spoken on my own authority, but the Father who sent me has himself given me a commandment — what to say and what to speak' (John 12:49). And again: 'The Son can do nothing of his own accord, but only what he sees the Father doing' (John 5:19). The Rechabite faithfulness to Jonadab's command over centuries is a faint image of the eternal Son's faithfulness to the Father's will.</p>",
  "7": "<p>'You shall live in tents all your days, so that you may live long in the land where you are strangers.' The Rechabite nomadic lifestyle keeps them as strangers and pilgrims — not settled into the land's comforts. Hebrews 11:13-14 reads the patriarchs as those who 'acknowledged that they were strangers and exiles on the earth,' seeking the heavenly city. Peter addresses believers as 'sojourners and exiles' (1 Pet 2:11). The Rechabite tent-dwelling is a figure of the Christian's provisional relationship to this age, awaiting the city whose builder and maker is God (Heb 11:10).</p>",
  "8": "<p>'We have obeyed the voice of Jonadab son of Rechab, our father, in everything he commanded us.' Total obedience — the mark of covenant faithfulness. Jesus's total obedience to the Father reaches its culmination in Gethsemane: 'Not my will, but yours be done' (Luke 22:42). The Rechabites who obeyed in everything are the OT shadow of the one who was 'obedient to the point of death, even death on a cross' (Phil 2:8). Complete covenant faithfulness, which Israel consistently failed, is finally achieved in the Son.</p>",
  "9": "<p>No houses, no vineyards, no fields, no seed — the Rechabites live without the permanent infrastructure of Canaanite civilization. The Son of Man has no place to lay his head (Matt 8:20): Jesus's itinerant ministry mirrors the nomadic faithfulness of the Rechabites, unattached to the settled patterns of a world that is passing away. The kingdom of God is not built by human real estate or agricultural investment but by the word of God planted in hearts (Mark 4:14-20).</p>",
  "10": "<p>'We have lived in tents and have obeyed and done all that our father Jonadab commanded us.' The Rechabites' summary: obedience expressed as a way of life, not merely a set of rules. Jesus summarizes his own obedience the same way: 'My food is to do the will of him who sent me and to accomplish his work' (John 4:34). Obedience is not an external compliance but a constitutive orientation — what one lives from and for. The Rechabites model the life-orientation that Christ embodies perfectly.</p>",
  "11": "<p>'When Nebuchadnezzar came up against the land, we came to Jerusalem for fear.' Even the faithfully obedient seek physical refuge in the face of overwhelming threat. Christ understands fear — he is the one who prayed in Gethsemane with sweat like drops of blood (Luke 22:44). The Rechabites' flight to Jerusalem for protection is the human impulse that Jesus transforms: 'Do not let your hearts be troubled. Believe in God; believe also in me' (John 14:1). The ultimate refuge is not the city's walls but the person of Christ.</p>",
  "12": "<p>The word of the LORD came to Jeremiah — the divine speech that draws out the lesson from the Rechabite encounter. The Rechabites did not know they were providing an object lesson for Israel's disobedience; God uses human faithfulness to his own purposes. In the same way, John 12:16 notes that the disciples did not understand what was happening at the triumphal entry until Jesus was glorified — events mean more than participants know, because the Word of God who orchestrates them sees the full picture.</p>",
  "13": "<p>'Will you not receive instruction and listen to my words?' The divine frustration with unteachable Israel becomes the thematic cry of the prophets. Jesus voices the same frustration over Jerusalem: 'O Jerusalem, Jerusalem, the city that kills the prophets and stones those who are sent to it! How often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!' (Matt 23:37). The divine longing to gather a people who will listen is fulfilled in those who hear Christ's voice and follow him (John 10:27).</p>",
  "14": "<p>'The command of Jonadab has been kept. To this day they drink none, because they obeyed their ancestor's command. But I have spoken to you persistently, and you have not listened to me.' Hebrews 1:1-2 draws the line from persistent prophetic speech to the final speech in the Son: 'Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son.' The persistence of divine speech, which the prophets embodied, culminates in the speech of the Son — who is not merely a messenger but the message itself.</p>",
  "15": "<p>'I have sent you all my servants the prophets, again and again ... but you did not incline your ear or listen to me.' Jesus tells the parable of the tenants (Matt 21:33-44; Luke 20:9-18): the owner sends servant after servant, all mistreated; finally he sends his son, saying 'they will respect my son' — and the tenants kill him. The parable is the story of Israel's response to the prophets, culminating in the killing of the Son. The persistent sending, which Jeremiah laments, is the sending that ends at the cross.</p>",
  "16": "<p>'The descendants of Jonadab have kept their father's command, but this people has not obeyed me.' The contrast: faithful Rechabites versus unfaithful Israel. Romans 5:19 states the ultimate resolution: 'As by the one man's disobedience the many were made sinners, so by the one man's obedience the many will be made righteous.' The disobedience of Israel (and of all humanity) is answered not by summoning deeper human obedience but by the obedience of Christ, who succeeds where all others failed.</p>",
  "17": "<p>'I called to them and they did not answer.' The divine speech that receives no response — the silence of human rejection. But Revelation 3:20 shows the persistent divine caller: 'Behold I stand at the door and knock. If anyone hears my voice and opens the door, I will come in to him and eat with him.' The calling continues even after rejection; the knocking continues at the door of each individual heart. The final judgment on those who do not answer is real, but the calling precedes it — and Christ himself is the one who calls.</p>",
  "18": "<p>'Because you have obeyed the command of Jonadab your father and kept all his instructions ... therefore thus says the LORD of hosts: Jonadab son of Rechab shall never fail to have a man standing before me.' Obedience that comes from loyal love to a father results in a permanent standing before God — the covenantal logic of Philippians 2:8-9: 'Being found in human form he humbled himself by becoming obedient to the point of death, even death on a cross. Therefore God has highly exalted him.' The Rechabite reward of permanent standing is the type of Christ's exaltation: because the Son was obedient, he is given the name above every name and stands forever before the Father as the mediator of all who come to God through him.</p>",
  "19": "<p>'Jonadab son of Rechab shall never fail to have a man standing before me.' The promise of permanent standing before God — the ultimate priestly privilege. Hebrews 7:25 makes this Christ's own identity: 'He always lives to make intercession' for those who draw near to God through him. And Romans 5:2 gives the standing to all who are in Christ: 'Through him we have also obtained access by faith into this grace in which we stand.' The never-failing man standing before God is Christ himself — and in him, all the Rechabite pattern's heirs stand with him.</p>"
}

CHRIST_36 = {
  "1": "<p>The fourth year of Jehoiakim — the year Nebuchadnezzar defeated Egypt at Carchemish (605 BCE), the turning point of the ancient Near East. This is the kairos moment when the word must be written down. Christ is the one in whom 'the time is fulfilled' (Mark 1:15) — the kairos of all kairos moments. The scroll that must be written in the year of geopolitical crisis is the prophetic counterpart to the incarnation: the word that must take form in the flesh at the precise fullness of time (Gal 4:4).</p>",
  "2": "<p>'Take a scroll and write in it all the words I have spoken to you ... from the day I first spoke to you in the days of Josiah until this day.' The comprehensive collection of the prophetic word — everything from the beginning gathered into one scroll. Jesus is the one who fulfills all the law and the prophets (Matt 5:17): every word spoken by God from Moses through Malachi finds its unity in him. The scroll containing all previous divine speech is the type of Christ in whom all Scripture coheres (Luke 24:44-45: everything written about me in the Law of Moses and the Prophets and the Psalms must be fulfilled).</p>",
  "3": "<p>'Perhaps the house of Judah will hear of all the disaster I intend to bring on them, so that each person will turn from his evil way, and I will forgive their iniquity and their sin.' The purpose of the written word: repentance and forgiveness. 2 Peter 3:9: 'The Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish, but that all should reach repentance.' The divine desire for repentance and forgiveness runs from Jeremiah through the cross: Christ's death is God's ultimate 'perhaps' — his most urgent appeal for human response, written in blood rather than ink.</p>",
  "4": "<p>Baruch wrote on a scroll everything Jeremiah dictated — the human scribe faithfully recording the divine word. Jesus promised the Spirit who would guide the disciples into all truth (John 16:13) and bring to their remembrance all that Jesus said (John 14:26). The apostolic writings are the new covenant scroll: the Spirit's dictation through human messengers, as Jeremiah dictated through Baruch. The inscripturation of the word requires human partnership with divine speech.</p>",
  "5": "<p>'I am banned; I cannot go to the house of the LORD.' Jeremiah confined — the prophet who cannot personally deliver the message. Christ is 'confined' in the deepest sense: 'I have a baptism to be baptized with, and how great is my distress until it is accomplished!' (Luke 12:50). The constraint is purposive — his confinement in the flesh, in the limits of human existence, is the very condition of his redemptive work. And the word goes out through others even when the prophet himself is prevented: the gospel travels through Spirit-filled witnesses even when its source has ascended.</p>",
  "6": "<p>'You go and read from the scroll you wrote at my dictation — the words of the LORD — to all the people in the LORD's house on a day of fasting.' The word proclaimed publicly in the temple on a day of fasting — the fast that marks Israel's consciousness of need before God. Jesus reads from the scroll of Isaiah in the synagogue (Luke 4:16-21) on the Sabbath: the public proclamation of the word in the sacred space is the pattern of Baruch reading Jeremiah's scroll. But where Baruch's reading is received by officials who go to warn the king, Jesus's reading results in attempted murder (Luke 4:28-30) — the final rejection pattern being established.</p>",
  "7": "<p>'Perhaps they will bring their petition before the LORD and each will turn from his evil way, for great is the anger and wrath of the LORD.' The urgent hope that the word will produce the repentance that averts wrath. Romans 10:14-17: 'How are they to believe in him of whom they have never heard? And how are they to hear without someone preaching? ... So faith comes from hearing, and hearing through the word of Christ.' The written word read aloud is the means of repentance; Baruch's public reading is the OT type of the apostolic proclamation — the word heard, believed, repentance following.</p>",
  "8": "<p>Baruch did exactly as Jeremiah commanded. Faithful messengership — doing precisely what was entrusted, without addition or subtraction. Paul describes the apostolic calling in the same terms: 'This is how one should regard us, as servants of Christ and stewards of the mysteries of God. Moreover it is required of stewards that they be found faithful' (1 Cor 4:1-2). The faithfulness of the messenger is not about the messenger's greatness but about the integrity of the transmission — the word reaching its hearers unchanged.</p>",
  "9": "<p>A fast proclaimed in Jerusalem — the people gathered before God in acknowledged need. Christ himself fasted forty days and forty nights (Matt 4:2) — entering the condition of human need and dependence before the Father. The fast is the physical expression of what the soul acknowledges before God: 'we have nothing apart from you.' Jesus teaches that true fasting is not performed for human approval but before the Father who sees in secret (Matt 6:16-18). The fifth-year fast in Jerusalem is the historical moment when Baruch reads — the receptive moment of hunger before the word.</p>",
  "10": "<p>Baruch read the words in the LORD's house — the word proclaimed in the sacred space where God's name dwells. Jesus taught daily in the temple (Luke 21:37-38); 'all the people were hanging on his words.' The temple as the house of prayer (Matt 21:13) is the proper place for the word of God to be proclaimed. But Jesus's body is the true temple (John 2:21), and from him the word goes out into all the world — the temple becomes a person, and the word proclaimed from the temple becomes the Word made flesh.</p>",
  "11": "<p>Micaiah heard all the words of the LORD from the scroll — the chain of hearing begins. The word of God always travels through those who hear and transmit: Jeremiah → Baruch → Micaiah → officials → the king. Romans 10:15-17 traces the same chain: preacher → word → hearing → faith. Each link in the chain is essential; the word that reaches Jehoiakim's court passes through multiple human hearers. The Incarnation is God himself entering the chain — no longer sending messengers but coming as the message.</p>",
  "12": "<p>The officials sat in the secretary's chamber — the center of political administration. The word of God reaches the halls of power: Elishama, Gemariah, Elnathan, and the other officials all hear. Jesus before the Sanhedrin, Paul before Felix and Festus and Agrippa (Acts 24-26), the apostles before the Jerusalem council — the word of the Lord consistently penetrates the chambers of power, and the powerful must decide what to do with it. The officials' response (sending for Baruch, hearing the scroll, being alarmed) is far better than the king's.</p>",
  "13": "<p>Micaiah reported to all the officials all the words he had heard. The faithful transmission of the word received — one who heard it brings it to others who have not yet heard. The chain of witness: 'What we have seen and heard we proclaim also to you' (1 John 1:3); 'We cannot but speak of what we have seen and heard' (Acts 4:20). The compulsion to report the word received is the pattern of all gospel witness — from Micaiah in the secretary's chamber to the apostles in the court.</p>",
  "14": "<p>The officials sent for Baruch — 'Take the scroll ... and come here.' The word is wanted, summoned. There are hearts in every generation who want to hear the word: Cornelius who sent for Peter (Acts 10:7-8), the Ethiopian eunuch reading Isaiah (Acts 8:28), Lydia whose heart the Lord opened (Acts 16:14). The officials' summoning of Baruch is the type of the spiritual hunger that draws out the messenger — the seeking that Christ promises will find (Matt 7:7-8).</p>",
  "15": "<p>'Sit down and read it to us.' The officials give the word an audience; they sit and listen. Mary sitting at Jesus's feet listening to his teaching (Luke 10:39) is the posture of the receptive hearer — what Jesus calls 'the good portion which will not be taken away from her.' Against Martha's distracted activity, the sitting and listening at the feet of the one who speaks the word is the essential act. The officials who say 'sit down and read' are, in that moment, doing what Mary did.</p>",
  "16": "<p>'When they heard all the words, they turned to one another in alarm.' The word of God that provokes fear and alarm — Hebrews 4:12: 'The word of God is living and active, sharper than any two-edged sword, piercing to the division of soul and spirit, of joints and marrow, and discerning the thoughts and intentions of the heart.' The officials' alarm is the right response to a word that exposes the true situation. The word of Christ is not comfortable; it is confronting — and the question is whether the alarm produces repentance or rejection.</p>",
  "17": "<p>'How did you write all these words? At his dictation?' The officials want to understand the mechanics of the word's origin. John 1:18: 'No one has ever seen God; the only God who is at the Father's side, he has made him known.' The question of how God's words come to human beings is answered definitively in the incarnation: not by a scribe taking dictation but by the Son who is himself the Word — the 'at his dictation' of all creation and all redemption. Jesus does not transmit a message; he is the message (John 14:6: I am the truth).</p>",
  "18": "<p>'He dictated all these words to me, and I wrote them in ink on the scroll.' The ink-on-scroll recording of the divine word is the OT medium; the NT medium is the same word written on hearts (2 Cor 3:3: written not with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts). Baruch's ink becomes the Spirit's inscription; the external scroll becomes the internal transformation. The word that Baruch copied is the word that Christ writes in the believer through the Spirit.</p>",
  "19": "<p>'Go and hide — you and Jeremiah — and let no one know where you are.' The officials protect the prophet and his scribe from the king's wrath. Matthew 2:13-15: the angel warns Joseph to take the child and flee to Egypt. The hidden prophet preserved from royal wrath is the type of the hidden Messiah preserved from Herod's sword. God hides his servants — 'He will hide me in his shelter in the day of trouble' (Ps 27:5) — because the word's survival is necessary for the purposes of redemption.</p>",
  "20": "<p>The officials stored the scroll in Elishama's chamber and went to report to the king. The word entrusted to a keeper while the official proceedings continue — the gospel entrusted to believers while the world's systems carry on. The scroll in Elishama's chamber will survive the king's burning because it is not the only copy: the word of God cannot be finally destroyed, even when the visible record is consumed. 1 Peter 1:23-25: 'The word of the Lord remains forever. And this word is the good news that was preached to you.'</p>",
  "21": "<p>The king sent Jehudi to get the scroll — the word brought into the presence of royal power. The same dynamic occurs at the passion: Jesus is brought before the powers of empire and religion. Every power in the world eventually must face the word of God — not as an abstraction but as a specific confrontation. Jehudi reading the scroll to Jehoiakim is the type of the word confronting power: the only question is the response.</p>",
  "22": "<p>Jehoiakim in his winter house, a fire burning in the fire pot. The comfortable warmth of the winter house — physical comfort that insulates from the word's demand. Jesus's parable of the rich fool (Luke 12:16-21) captures the same insulation: stored-up goods, bodily ease, 'eat, drink, and be merry.' The fire that should burn in the heart (Luke 24:32: 'Did not our hearts burn within us while he talked to us on the road?') burns instead in the fire pot — physical warmth that replaces spiritual reception.</p>",
  "23": "<p>Each time Jehudi read three or four columns, the king cut off the section and threw it into the fire — until the entire scroll was consumed. The systematic destruction of the written word of God: Jehoiakim's knife cutting the columns is the type of every attempt to suppress, destroy, or silence the gospel. The burning of the scroll is also the type of the crucifixion: the Word made flesh is crucified. Isaiah 40:8: 'The grass withers, the flower fades, but the word of our God will stand forever.' The burned scroll is rewritten; the crucified Word is raised. The cross is Jehoiakim's knife on the ultimate scale — and the resurrection is the re-dictated scroll.</p>",
  "24": "<p>'Neither the king nor any of his servants who heard all these words was afraid, nor did they tear their garments.' The complete absence of the response the word demands — no fear, no repentance, no torn garments (the sign of mourning and contrition). Acts 7:57-58: when Stephen delivered his prophetic speech, 'they stopped their ears and rushed together at him and cast him out of the city and stoned him.' The hardened heart that meets the word with violence rather than repentance is the consistent pattern: Jehoiakim → the Sanhedrin → all who reject the crucified Christ.</p>",
  "25": "<p>Elnathan and Delaiah and Gemariah pleaded with the king not to burn the scroll — he would not listen. There is always a remnant who attempt to preserve the word, who intercede for its reception. The 7,000 who have not bowed the knee to Baal (1 Kgs 19:18; Rom 11:4-5) are the minority who carry the word through periods of official rejection. The officials who plead with Jehoiakim are the type of the remnant by grace — those in whom the divine mercy has produced a different hearing, preserved through the faithfulness of God.</p>",
  "26": "<p>'The king commanded ... to seize Baruch the scribe and Jeremiah the prophet. But the LORD hid them.' God's protection of his servants from the wrath of human power. The resurrection is the ultimate 'but the LORD hid them': human power kills the Word made flesh, but God does not leave him in the tomb. Acts 2:24: 'God raised him up, loosing the pangs of death, because it was not possible for him to be held by it.' The scroll is burned but the scribes are hidden; Christ is crucified but raised — the word of God outlasts every attempt to silence it.</p>",
  "27": "<p>'After the king had burned the scroll ... the word of the LORD came to Jeremiah.' The burning does not silence the word — it comes again, immediately. John 1:5: 'The light shines in the darkness, and the darkness has not overcome it.' The word that was burned (type: crucified) comes again (type: risen). The resurrection is not a new message but the same message, vindicated and re-given: 'He is risen' is the re-dictation of the burned scroll. The word that Jehoiakim tried to destroy is immediately reconstituted in the divine speech.</p>",
  "28": "<p>'Take another scroll and write on it all the same words that were in the first scroll, the one Jehoiakim burned.' The command to re-inscribe the destroyed word — the resurrection pattern. 1 Peter 1:23-25: 'You have been born again, not of perishable seed but of imperishable, through the living and abiding word of God ... The word of the Lord remains forever.' The word that cannot be destroyed is made permanent not by human preservation but by divine imperishability. The scroll is burned; the word endures; another scroll is taken — because the word's existence does not depend on the first copy.</p>",
  "29": "<p>'Why have you written in it that the king of Babylon will certainly come and destroy this land?' Jehoiakim's objection to the word: it says uncomfortable things about power. The powers that crucify Christ object to the same thing: 'He said he was the Son of God' (John 19:7); 'We found this man misleading our nation' (Luke 23:2). The word of God that announces judgment on present powers is always the word that power seeks to silence — but the silence fails, because the judgment announced comes true.</p>",
  "30": "<p>'He will have no one to sit on the throne of David.' Jehoiakim's dynastic pretension — the king who would silence God's word loses his own succession. The contrast with the Davidic promise in Jeremiah 33:17 is stark: David's line will never fail a man to sit on the throne — because that man is ultimately Christ. Those who set themselves against the word of God lose what they sought to preserve through that opposition; those who receive the word and the King it announces share in his eternal reign (Rev 22:5: they will reign forever and ever).</p>",
  "31": "<p>'I will punish him and his offspring and his servants for their iniquity.' The judgment falls not only on the individual but on those who participate in covenant-breaking. Yet 2 Cor 5:19-21 reverses this: 'In Christ God was reconciling the world to himself, not counting their trespasses against them ... For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God.' The punishment that should fall on Jehoiakim's offspring — on all who reject the word — has fallen on Christ, so that those who receive the word receive not punishment but righteousness.</p>",
  "32": "<p>'Then Jeremiah took another scroll ... and wrote on it at Jeremiah's dictation all the words of the scroll that Jehoiakim had burned. And many similar words were added to them.' The re-dictated scroll is not a mere copy — it contains everything before plus more. The resurrection gospel is the same word as the prophetic word, but fuller: Hebrews 1:1-2 traces the movement from the partial prophetic speech to the definitive speech in the Son. The scroll with additions is the type of the full canon — the burned-and-rewritten word of God that is richer than what came before, with everything the prophets said now illuminated by the passion, death, and resurrection of Jesus Christ. The word Jehoiakim burned is the word that outlasts all empires, all fire pots, all scribe's knives — living and abiding forever (1 Pet 1:23).</p>"
}

def main():
    c = load_comm("christ", "jeremiah")
    merge_comm(c, {"33": CHRIST_33, "34": CHRIST_34, "35": CHRIST_35, "36": CHRIST_36})
    save_comm("christ", "jeremiah", c)
    total = sum(len(v) for v in c.values())
    print(f"  jeremiah mkt-christ: {len(c)} chapters, {total} verses total")

if __name__ == "__main__":
    main()
